android.extraProguardRules:
# Phase B+ hardening 2026-05-20
# See lib/security/README.md for rationale

-keep class com.stripe.android.** { *; }
-keep interface com.stripe.android.** { *; }
-keepclassmembers class com.stripe.android.model.** { *; }

-keep class io.github.jan.supabase.** { *; }
-keepclassmembers class kotlinx.serialization.** { *; }
-keepclasseswithmembers class * { @kotlinx.serialization.Serializable <fields>; }

-keep class io.sentry.** { *; }
-keep class io.sentry.android.** { *; }

-keep class expo.modules.** { *; }
-keep class expo.modules.kotlin.** { *; }
-keep class expo.modules.securestore.** { *; }

-keep class com.facebook.react.bridge.** { *; }
-keep class com.facebook.react.fabric.** { *; }
-keep class com.facebook.hermes.unicode.** { *; }
-keep class com.facebook.jni.** { *; }

-keepattributes *Annotation*, EnclosingMethod, Signature, InnerClasses, SourceFile, LineNumberTable
